+    fn doc_version_hash_distinct() {
+        use std::collections::HashSet;
+        let mut set = HashSet::new();
+        set.insert(DocVersion(100));
+        set.insert(DocVersion(200));
+        set.insert(DocVersion(100)); // duplicate
+        assert_eq!(set.len(), 2);
+    }
